import React, { useState } from 'react';
import logo from '../Assets/Car 24 logo.png';
import CarSlider from '../components/CarSlider';
import './ComingSoon.css';

const ComingSoon = () => {
  const [email, setEmail] = useState('');

  const handleNotify = () => {
    if (email) {
      alert(`Thank you! We will notify you at ${email}`);
      setEmail('');
    } else {
      alert('Please enter your email address');
    }
  };

  const carImages = [
    'https://images.unsplash.com/photo-1605559424843-9e4c228bf1c2?w=400&h=300&fit=crop',
    'https://images.unsplash.com/photo-1552519507-da3b142c6e3d?w=400&h=300&fit=crop',
    'https://images.unsplash.com/photo-1583121274602-3e2820c69888?w=400&h=300&fit=crop',
    'https://images.unsplash.com/photo-1617531653332-bd46c24f2068?w=400&h=300&fit=crop',
    'https://images.unsplash.com/photo-1606664515524-ed2f786a0bd6?w=400&h=300&fit=crop',
    'https://images.unsplash.com/photo-1614200187524-dc4b892acf16?w=400&h=300&fit=crop'
  ];

  return (
    <div className="coming-soon-wrapper">
      <div className="coming-soon-section">
        {/* Left Content - Brand & Details */}
        <div className="content-left">
          <div className="logo-container">
            <img src={logo} alt="Car24 Travels - Self Drive" className="brand-logo" />
          </div>
          
          <h1 className="main-title">COMING SOON</h1>
          
          <p className="brand-description">
            Your premium car rental experience is on the way — no surge, 
            no hidden fees, just pure driving pleasure.
          </p>
          
          <div className="features-grid">
            <div className="feature-card">
              <span className="feature-icon">⚡</span>
              <div className="feature-text">
                <h4>Electric & Hybrid</h4>
                <p>Zero-emission rides</p>
              </div>
            </div>
            
            <div className="feature-card">
              <span className="feature-icon">🔑</span>
              <div className="feature-text">
                <h4>Keyless Pickup</h4>
                <p>24/7 self-service</p>
              </div>
            </div>
            
            <div className="feature-card">
              <span className="feature-icon">🛡️</span>
              <div className="feature-text">
                <h4>Fully Insured</h4>
                <p>Premium coverage</p>
              </div>
            </div>
            
            <div className="feature-card">
              <span className="feature-icon">🗺️</span>
              <div className="feature-text">
                <h4>Unlimited Mileage</h4>
                <p>Explore without limits</p>
              </div>
            </div>
          </div>
          
          <div className="email-signup-container">
            <div className="email-input-group">
              <input 
                type="email" 
                placeholder="Enter your email for updates"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                onKeyPress={(e) => e.key === 'Enter' && handleNotify()}
                className="email-input"
              />
              <button onClick={handleNotify} className="notify-button">
                Notify Me
              </button>
            </div>
          </div>
          
          <div className="credit-text">
            Powered by <strong>Stackenzo</strong>
          </div>
        </div>

        {/* Right Content - Car Slider */}
        <div className="content-right">
          <CarSlider carImages={carImages} />
        </div>
      </div>
    </div>
  );
};

export default ComingSoon;
